import os
from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core
from src.utils.prism_config import (
    resolve_cfg, get_departments, resolve_dept_folder,
    get_entity_scenefiles_root, build_abbrev_map
)

class PrismGetTasksNode(BaseNode):
    name = "Prism: Get Tasks"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("entity", "dict")
        self.add_input("department", "string", widget_type="text", default="")
        self.add_output("tasks", "list")
        self.add_output("count", "int")
        self.add_output("departments", "list")

    def _tasks_from_scenefiles(self, core, entity, dept_abbrev, dept_defs):
        files = core.entities.getScenefiles(entity) or []
        if not files:
            return []
        abbrev_map = build_abbrev_map(dept_defs)
        seen = set()
        tasks = []
        for sf in files:
            if not isinstance(sf, dict):
                continue
            sf_dept = (sf.get('department', sf.get('step', '')) or '').lower()
            if dept_abbrev and sf_dept not in (dept_abbrev, abbrev_map.get(sf_dept, {}).get('abbreviation', '')):
                entry = abbrev_map.get(sf_dept)
                if not entry or entry.get('abbreviation') != dept_abbrev:
                    continue
            task = sf.get('task', '')
            if task and task not in seen:
                seen.add(task)
                tasks.append(task)
        return tasks

    def _tasks_from_disk(self, scenes_root, dept_abbrev):
        all_dirs = {e.name: e.path for e in os.scandir(scenes_root) if e.is_dir()}
        if not dept_abbrev:
            return sorted(all_dirs.keys())
        dept_dir = all_dirs.get(dept_abbrev)
        if not dept_dir:
            self.log_error(f"dept folder '{dept_abbrev}' not in {scenes_root} — found: {sorted(all_dirs)}")
            return []
        return sorted(e.name for e in os.scandir(dept_dir) if e.is_dir())

    def _default_tasks_from_cfg(self, dept_abbrev, dept_defs):
        for d in dept_defs:
            if d.get('abbreviation') == dept_abbrev:
                return list(d.get('defaultTasks', []))
        return []

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        entity = inputs.get('entity') or {}
        dept_input = (inputs.get('department') or '').strip()
        if core is None:
            self.log_error('No PrismCore found.')
            return {'tasks': [], 'count': 0, 'departments': []}
        cfg_path = resolve_cfg(core=core, entity=entity)
        entity_type = entity.get('type', 'shot')
        dept_defs = get_departments(core, cfg_path, entity_type)
        dept_abbrev = resolve_dept_folder(dept_input, dept_defs) if dept_input else ''
        if dept_input and not dept_abbrev:
            dept_abbrev = dept_input.lower()
        self.log_info(f"dept input='{dept_input}' -> abbrev='{dept_abbrev}' (cfg={cfg_path})")
        tasks = []
        try:
            tasks = self._tasks_from_scenefiles(core, entity, dept_abbrev, dept_defs)
            self.log_info(f'getScenefiles: {len(tasks)} task(s)')
        except Exception as e:
            self.log_info(f'getScenefiles error: {e}')
        if not tasks:
            scenes_root = get_entity_scenefiles_root(entity, core, cfg_path)
            if scenes_root:
                tasks = self._tasks_from_disk(scenes_root, dept_abbrev)
                self.log_info(f'disk tasks: {tasks}')
            elif dept_abbrev and dept_defs:
                tasks = self._default_tasks_from_cfg(dept_abbrev, dept_defs)
                self.log_info(f'default tasks from pipeline.json: {tasks}')
        dept_names = [d['name'] for d in dept_defs] if dept_defs else []
        self.log_info(f'result tasks: {tasks}')
        return {'tasks': tasks, 'count': len(tasks), 'departments': dept_names}

def register_node():
    return PrismGetTasksNode
